import React, { useState } from "react";

import {
  Play,
  Section,
  Container,
  VideoWrapper,
  PreviewImage,
  PlayButtonWrapper,
} from "./Style";

const videoId = "Z4J-xz3EujE";
const thumbnail = `https://i.ytimg.com/vi_webp/${videoId}/maxresdefault.webp`;

function Video() {
  const [isPlaying, setIsPlaying] = useState(false);

  return (
    <Section id="video">
      <Container>
        <VideoWrapper>
          {!isPlaying ? (
            <div onClick={() => setIsPlaying(true)}>
              <PreviewImage
                src={thumbnail}
                alt="Roman Storm fight story #FreeRomanStorm"
              />
              <PlayButtonWrapper>
                <Play name="play" size="xl" />
              </PlayButtonWrapper>
              play
            </div>
          ) : (
            <iframe
              width="100%"
              height="100%"
              src={`https://www.youtube.com/embed/${videoId}?autoplay=1`}
              title="Roman Storm fight story #FreeRomanStorm"
              frameBorder="0"
              allow="accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture; web-share"
              referrerPolicy="strict-origin-when-cross-origin"
              allowFullScreen
            ></iframe>
          )}
        </VideoWrapper>
      </Container>
    </Section>
  );
}

export { Video };
