import React from "react";
import { useStaticQuery, graphql } from "gatsby";

import { link } from "constant";

import { Icon } from "components/ui";

import {
  Wrap,
  Info,
  Title,
  Action,
  ImgWrap,
  Section,
  InfoWrap,
  InfoText,
  Container,
  ActionText,
  DonateLink,
  Composition,
  ActionTitle,
  StyledImage,
  ActionContent,
} from "./Style";

const Whois = () => {
  const data = useStaticQuery(graphql`
    query {
      roman: file(relativePath: { eq: "images/whois/whois-roman.jpg" }) {
        childImageSharp {
          fluid(maxWidth: 307, quality: 100) {
            ...GatsbyImageSharpFluid_withWebp
          }
        }
      }
    }
  `);

  return (
    <Section id="whoIs">
      <Wrap>
        <Container>
          <Info>
            <Title>Who is Roman Storm?</Title>
            <InfoWrap>
              <InfoText>
                With a&nbsp;strong background in&nbsp;software development and
                blockchain technology, Roman Storm has been a&nbsp;vocal
                advocate for the importance of&nbsp;privacy in&nbsp;the
                blockchain ecosystem. Storm&rsquo;s innovative work has made
                significant contributions to&nbsp;the ongoing discussions about
                the balance between privacy and regulatory compliance
                in&nbsp;the evolving landscape of&nbsp;cryptocurrencies.
              </InfoText>
              <InfoText>
                Despite facing the DOJ charges, Storm is&nbsp;committed
                to&nbsp;challenging the government&rsquo;s overreach and
                advancing the principles of&nbsp;decentralization.
              </InfoText>
              <InfoText>
                Help Roman in&nbsp;his flight against criminalizing software
                development and right to&nbsp;privacy!
              </InfoText>
            </InfoWrap>

            <Composition>
              <ImgWrap>
                <StyledImage
                  fluid={data.roman.childImageSharp.fluid}
                  alt="RomanStorm image"
                />
              </ImgWrap>
            </Composition>
          </Info>
        </Container>
        <Action>
          <ActionContent>
            <ActionTitle>Your chance to help!</ActionTitle>
            <ActionText>
              Lobby the Trump administration to <strong>#FreeRomanStorm</strong>
            </ActionText>
          </ActionContent>

          <DonateLink href={link.TWEET}>
            Like and Retweet
            <Icon name="arrow" rotate="-90deg" />
          </DonateLink>
        </Action>
      </Wrap>
    </Section>
  );
};

export { Whois };
