import React from "react";
import { useStaticQuery, graphql } from "gatsby";

import { menu } from "constant";

import { Href, Icon, ScrollTo } from "components/ui";

import {
  Section,
  DonateLink,
  Container,
  Info,
  Title,
  InfoWrap,
  InfoText,
  Composition,
  ImgWrap,
  StyledImage,
  InfoLink,
  InfoAction,
  HashTag,
  InfoSubTitle,
} from "./Style";

const Intro = () => {
  const data = useStaticQuery(graphql`
    query {
      roman: file(relativePath: { eq: "images/intro/intro-roman.webp" }) {
        childImageSharp {
          fluid(maxWidth: 307, quality: 100) {
            ...GatsbyImageSharpFluid_withWebp
          }
        }
      }
    }
  `);

  return (
    <Section id="intro">
      <Container>
        <Info>
          <Composition>
            <ImgWrap>
              <StyledImage
                fluid={data.roman.childImageSharp.fluid}
                alt="RomanStorm image"
              />
            </ImgWrap>
          </Composition>

          <Title>
            Free
            <br />
            Roman
            <br />
            Storm
          </Title>
          <InfoSubTitle>
            <HashTag translate="no" className="notranslate">
              #FreeRomanStorm
            </HashTag>
          </InfoSubTitle>

          <InfoWrap>
            <InfoText>
              The U.S.&nbsp;Government arrested Roman Storm
              on&nbsp;August&nbsp;23, 2023 in&nbsp;an early morning raid
              on&nbsp;his home in&nbsp;Seattle and charged him with conspiracy
              to&nbsp;commit unlicensed money transmitting, money laundering,
              and sanctions evasion, all of&nbsp;which arise from Roman&rsquo;s
              role in&nbsp;developing the privacy tool Tornado Cash. If
              convicted, Storm could face up&nbsp;to&nbsp;45&nbsp;years
              in&nbsp;prison.
            </InfoText>
            <InfoText>
              The U.S.&nbsp;Government&rsquo;s prosecution of&nbsp;Tornado Cash
              co-founder Roman Storm, set to&nbsp;begin on&nbsp;
              <Href href="https://www.coindesk.com/policy/2024/11/01/tornado-cash-developer-roman-storms-trial-pushed-to-april">
                April 14th in&nbsp;SDNY
              </Href>
              , threatens to set a&nbsp;dangerous precedent for open-source
              developers, free speech, and financial privacy
              in&nbsp;decentralized systems.
            </InfoText>

            <InfoAction>
              <ScrollTo to={menu.tweet} href="/#tweet">
                <DonateLink>
                  Help Roman
                  <Icon name="arrow" rotate="-90deg" />
                </DonateLink>
              </ScrollTo>
              <ScrollTo to={menu.allegations} href="#allegations">
                <InfoLink>Learn More</InfoLink>
              </ScrollTo>
            </InfoAction>
          </InfoWrap>
        </Info>
      </Container>
    </Section>
  );
};

export { Intro };
