import React, { useMemo, useState } from "react";

import { menu } from "constant";

import { Icon, LogoLink, ScrollTo } from "components/ui";

import {
  Nav,
  List,
  Wrap,
  Burger,
  Overlay,
  ListItem,
  Container,
  DonateLink,
  Connection,
  CustomLink,
  ListItemButton,
  ConnectionMobile,
} from "./Style";

const Header = () => {
  const [isOpenNav, setOpenNav] = useState(false);

  const handleClick = () => {
    setOpenNav(!isOpenNav);
    document.body.style.overflowY = isOpenNav ? "unset" : "hidden";
    document.body.style.overflowX = "hidden";
  };

  const handleClickMenu = () => {
    setOpenNav(!isOpenNav);
    document.body.style.overflowY = "unset";
  };

  const links = useMemo(() => {
    return [
      { to: menu.whoIs, href: "/#whoIs", text: "Who is Roman Storm?" },
      { to: menu.allegations, href: "/#allegations", text: "Allegations" },
      { to: menu.important, href: "/#important", text: "Why is it important?" },
      { to: menu.timeline, href: "/#timeline", text: "Timeline" },
      { to: menu.community, href: "/#community", text: "Learn more" },
      { to: menu.faq, href: "/#faq", text: "FAQ" },
    ];
  }, []);

  return (
    <Wrap id="appHeader">
      <Container>
        <LogoLink />

        <Nav role="navigation" aria-label="Navigation" isOpen={isOpenNav}>
          <List>
            {links.map((link) => (
              <ListItem key={link.to}>
                <ScrollTo to={link.to} href={link.href}>
                  <ListItemButton onClick={handleClickMenu}>
                    <CustomLink>{link.text}</CustomLink>
                  </ListItemButton>
                </ScrollTo>
              </ListItem>
            ))}
          </List>

          <Connection>
            <ScrollTo to={menu.tweet} href="/#tweet">
              <DonateLink>
                Help Roman
                <Icon name="arrow" rotate="-90deg" />
              </DonateLink>
            </ScrollTo>
          </Connection>
        </Nav>

        <ConnectionMobile>
          <ScrollTo to={menu.tweet} href="/#tweet">
            <DonateLink>
              Help Roman
              <Icon name="arrow" rotate="-90deg" />
            </DonateLink>
          </ScrollTo>
        </ConnectionMobile>

        <Burger isOpen={isOpenNav} onClick={handleClick} />
        <Overlay
          isOpen={isOpenNav}
          onClick={handleClickMenu}
          role="presentation"
        />
      </Container>
    </Wrap>
  );
};

export { Header };
